const B='https://data.designflow.app'
const tok=(await (await fetch(B+'/auth/login',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({email:process.env.DX_ADMIN_EMAIL,password:process.env.DX_ADMIN_PASSWORD})})).json()).data.access_token
const roles=(await (await fetch(B+'/roles?fields=id,name,policies.policy.id&limit=-1',{headers:{Authorization:'Bearer '+tok}})).json()).data
const polRole=new Map(); for(const r of roles) for(const p of (r.policies||[])) if(p?.policy?.id) polRole.set(p.policy.id, r.name)
const perms=(await (await fetch(B+'/permissions?filter[collection][_eq]=product&filter[action][_eq]=read&fields=policy,fields&limit=-1',{headers:{Authorization:'Bearer '+tok}})).json()).data
const NEW=['clickup_space_id','clickup_space_name','clickup_folder_id','clickup_folder_name','clickup_list_id','clickup_creator_id','clickup_creator_name','clickup_time_estimate_ms','clickup_orderindex']
for(const p of perms){
  const w=Array.isArray(p.fields)&&p.fields.includes('*')
  const have=w?'ALL(*)':(NEW.every(f=>p.fields?.includes(f))?'ALL 9 new fields':'MISSING: '+NEW.filter(f=>!p.fields?.includes(f)).join(','))
  console.log('role',(polRole.get(p.policy)||'?').padEnd(16),'policy',String(p.policy).slice(0,8),'->',have)
}
